1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Step = QuoteStep;
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	
9	const basePremium = (item: Item): number => {
10	  if (item.type === "sword") return 100;
11	  if (item.type === "amulet") return 60;
12	  return 0;
13	};
14	
15	const roundUp = (n: number): number => Math.ceil(Math.round(n * 1e6) / 1e6);
16	
17	const itemPremium = (item: Item): number =>
18	  basePremium(item) * (1 + FIRST_INSURANCE_SURCHARGE);
19	
20	const quotePremium = (items: Item[]): number => {
21	  const itemTotal = items.reduce((sum, item) => sum + itemPremium(item), 0);
22	  return roundUp(itemTotal + PROCESSING_FEE);
23	};
24	
25	export const run = (scenario: Scenario): { results: { premium: number }[] } => {
26	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
27	  return { results };
28	};
